// Parse the LLM JSON output and merge in any user overrides (phone, linkedin, etc.)
let raw = $input.first().json.text || '';
raw = raw.trim();
if (raw.startsWith('```')) {
  raw = raw.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  const match = raw.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('LLM did not return parseable JSON: ' + e.message);
  parsed = JSON.parse(match[0]);
}

const overrides = $('Webhook').first().json.body.user_overrides || {};
parsed.contact = parsed.contact || {};
for (const [k, v] of Object.entries(overrides)) {
  if (v && typeof v === 'string' && v.trim()) {
    parsed.contact[k] = v.trim();
  }
}

return [{ json: { resume_full_data: parsed } }];

// Fan out: one item per selected career, carrying the full resume + webhook body
const resume = $('Merge User Overrides').first().json.resume_full_data;
const body = $('Webhook').first().json.body;
const careers = body.selected_careers || [];
return careers.map((c) => ({
  json: {
    ...body,
    career: c,
    resume_full_data: resume,
  },
}));

// Build the must-include keyword list from enriched_jobs (capped at 25)
const enrichedItems = $('Fetch Enriched Jobs').all();
const enriched = enrichedItems.length > 0 ? enrichedItems[0].json : {};
const keywords = new Set();

(enriched.technical_skills || []).forEach(k => k && keywords.add(k));
(enriched.soft_skills || []).forEach(k => k && keywords.add(k));
(enriched.typical_tasks || []).forEach(k => k && keywords.add(k));
(enriched.certifications_requirements || '').split(/[,;\n]/).forEach(k => {
  const t = (k || '').trim();
  if (t) keywords.add(t);
});

// Build a flattened personality text block for the LLM prompts
const personality = $('Fetch Personality Sections').all()
  .map(i => (i.json.content || '').trim())
  .filter(Boolean)
  .join('\n\n---\n\n');

const narrativeItems = $('Fetch Career Narrative').all();
const narrative = narrativeItems.length > 0 ? (narrativeItems[0].json.content || '') : '';

const current = $('Split In Batches').item.json;

return [{
  json: {
    ...current,
    keywords: Array.from(keywords).slice(0, 25),
    personality_voice: personality,
    career_narrative: narrative,
  },
}];

parameters.text:
=You re-frame a candidate's existing résumé toward a specific target career.

NEVER invent facts. NEVER add experience the candidate doesn't have. Your job is to choose which existing bullets to lift, re-order them, and rewrite the summary so the résumé tells the strongest possible story for THIS target.

Output ONLY a JSON object matching this schema (no markdown, no commentary):

{
  "contact": {},
  "summary": "",
  "experience": [
    { "title": "", "company": "", "location": "", "start": "", "end": "", "current": false, "bullets": [""] }
  ],
  "skills_grouped": {
    "technical": [], "tools": [], "soft": [], "languages": []
  },
  "education": [],
  "certifications": [],
  "highlights": [""]
}

Rules:
- contact: copy from input unchanged.
- summary: 3-4 sentences, written in the voice cues provided. Lead with the strongest claim to the target role. Avoid clichés ("results-driven", "passionate").
- experience: keep every role the candidate held. Within each role, re-order bullets to lead with what matters for the target. You can rewrite phrasing (active voice, quantify if the number is already in the source) but never fabricate metrics.
- skills_grouped: distribute into technical / tools / soft / languages buckets, prioritising overlap with the keyword list.
- education + certifications: copy unchanged.
- highlights: 2-3 standout one-liners pulled from experience.

TARGET CAREER: {{ $json.career.career_title }}

WHY-SUITED NARRATIVE (from their assessment, optional):
{{ $json.career_narrative || 'Not available.' }}

PERSONALITY VOICE CUES:
{{ $json.personality_voice || '' }}

MUST-INCLUDE KEYWORDS (try to land these):
{{ JSON.stringify($json.keywords) }}

CANDIDATE'S CURRENT RÉSUMÉ (JSON):
{{ JSON.stringify($json.resume_full_data) }}

=Write a tailored cover letter for the target role. Output ONLY (no markdown, no commentary):

{
  "greeting": "Dear Hiring Team,",
  "opening": "",
  "body_paragraphs": ["", ""],
  "closing": ""
}

Rules:
- 3-4 paragraphs total. Tight. Hiring managers skim.
- Pull specific examples from the résumé: names of companies, projects.
- Voice should match the personality cues provided.
- Never say "I am writing to apply for...". Lead with substance.
- No fake names in the greeting.

TARGET CAREER: {{ $('Build Keyword List').item.json.career.career_title }}

WHY-SUITED NARRATIVE:
{{ $('Build Keyword List').item.json.career_narrative || '' }}

PERSONALITY VOICE CUES:
{{ $('Build Keyword List').item.json.personality_voice || '' }}

TAILORED RÉSUMÉ:
{{ $json.text }}

