// Assemble the final payload for the custom_resumes row update.
// At this point we have ATS output for sure, and (optionally) a cover letter.

function safeParseJson(raw) {
  if (!raw) return null;
  let s = String(raw).trim();
  if (s.startsWith('```')) {
    s = s.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  }
  try { return JSON.parse(s); }
  catch (e) {
    const m = s.match(/\{[\s\S]*\}/);
    return m ? JSON.parse(m[0]) : null;
  }
}

const atsRaw = $('ATS Optimisation Pass').item.json.text;
const ats = safeParseJson(atsRaw);
if (!ats) throw new Error('Could not parse ATS pass output');

let cover = null;
try {
  const coverItems = $items('Cover Letter');
  if (coverItems && coverItems.length > 0) {
    cover = safeParseJson(coverItems[0].json.text);
  }
} catch (e) { cover = null; }

const career = $('Build Keyword List').item.json.career;

return [{
  json: {
    custom_resume_id: career.custom_resume_id,
    resume_json: ats.resume_json,
    cover_letter_json: cover,
    ats_score: ats.ats_score,
    keyword_coverage: ats.keyword_coverage,
  },
}];
